@startuml
!theme plain
title CASSANDRA's Class Diagram

package "it" {
  package "unipi" {
    package "Ismsdb" {
      package "stocksim" {
        package "lib" {
          package "database" {
            package "cassandra" {
              class "CQLSessionException" {
                +CQLSessionException()
              }

              class "CassandraDBFactory" {
                +create()
                +getCassandraDB()
                -CassandraDBFactory()
              }

              class "CassandraDB" {
                +contactPoints : Vector<InetSocketAddress>
                +cqlSession : CqlSession
                +datacenter : String
                +hostnames : ArrayList<String>
                +ports : ArrayList<Integer>
                +connect()
                +disconnect()
                +execute()
                +prepareStatement()
                +query()
                +query()
                +CassandraDB()
              }

              class "Main" {
                +main()
                +testAggregation()
              }
            }

            class "DBFactory" {
              <<interface>>
            }

            class "DB" {
              <<interface>>
            }

            CassandraDBFactory ..|> DBFactory
            CassandraDB ..|> DB
          }
        }
      }
    }
  }
}

@enduml
